prompt:
너는 GLP-Care 투약 관리 앱의 사용자 테스트를 수행하는 UX 리서처다.

## 페르소나 A
- 30대 직장인
- 주 1회 위고비 0.5mg 피하주사 (금요일)
- 매일 아침 드시모네(유산균) 1정
- 하루 2회(아침 8시 / 저녁 22시) 항우울제 복용
- 스마트폰 앱은 자주 쓰지만 UI가 복잡하면 바로 이탈함
- 병원 다음 날 약 빼먹는 경우 잦음

## 테스트 대상 코드 (injection.tsx)
```tsx
import { useState } from "react";
import {
  Alert,
  KeyboardAvoidingView,
  Modal,
  Platform,
  SafeAreaView,
  ScrollView,
  StyleSheet,
  Text,
  TextInput,
  TouchableOpacity,
  View,
} from "react-native";
import { createInjection } from "../../src/lib/api";

type MedForm = "oral" | "injection" | "other";
type FreqType = "daily" | "weekly";
type Screen = "main" | "manage" | "add";
type TimeSlot = "morning" | "lunch" | "evening" | "bedtime";
type MealCondition = "fasting" | "before" | "after" | "any";
type LogStatus = "taken" | "missed" | "pending";
type DayStatus = "complete" | "partial" | "missed" | "none" | "pending";

interface MedSchedule {
  id: string;
  timeSlot: TimeSlot;
  timeDetail: string;
}

interface Medication {
  id: string;
  name: string;
  form: MedForm;
  dosage: string;
  frequency: FreqType;
  frequencyDays: string[];
  schedules: MedSchedule[];
  condition: MealCondition;
  memo: string;
  colorIndex: number;
  isActive: boolean;
  createdAt: string;
}

interface MedLog {
  id: string;
  medicationId: string;
  scheduleId: string;
  date: string;
  status: LogStatus;
  checkedAt: string | null;
}

interface CheckItem {
  medicationId: string;
  scheduleId: string;
  name: string;
  dosage: string;
  condition: MealCondition;
  timeSlot: TimeSlot;
  timeDetail: string;
  color: string;
  log: MedLog | null;
}

interface MedDraft {
  name: string;
  form: MedForm;
  dosage: string;
  frequency: FreqType;
  frequencyDays: string[];
  schedules: MedSchedule[];
  condition: MealCondition;
  memo: string;
}

interface MainScreenProps {
  medications: Medication[];
  logs: MedLog[];
  calendarYear: number;
  calendarMonth: number;
  setCalendarYear: (value: number) => void;
  setCalendarMonth: (value: number) => void;
  onGoManage: () => void;
  onGoAdd: () => void;
  onToggleLog: (medicationId: string, scheduleId: string, date: string) => void;
  onSelectDate: (date: string) => void;
}

interface ManageScreenProps {
  medications: Medication[];
  onBack: () => void;
  onGoAdd: () => void;
  onDelete: (id: string) => void;
}

interface AddScreenProps {
  onBack: () => void;
  onSave: (draft: MedDraft) => Promise<void>;
}

interface CheckCardProps {
  item: CheckItem;
  onToggle: (medicationId: string, scheduleId: string, date: string) => void;
  date: string;
}

interface CalendarViewProps {
  year: number;
  month: number;
  medications: Medication[];
  logs: MedLog[];
  today: string;
  onPrevMonth: () => void;
  onNextMonth: () => void;
  onSelectDate: (date: string) => void;
}

interface DateDetailSheetProps {
  visible: boolean;
  date: string | null;
  medications: Medication[];
  logs: MedLog[];
  onClose: () => void;
  onToggleLog: (medicationId: string, scheduleId: string, date: string) => void;
}

const PRIMARY = "#10B981";
const BG = "#F8FAFC";
const CARD = "#FFFFFF";
const TEXT = "#0F172A";
const SUBTEXT = "#64748B";
const BORDER = "#E2E8F0";
const MUTED = "#F1F5F9";
const SUCCESS_BG = "#D1FAE5";
const SUCCESS_TEXT = "#059669";
const WARNING_BG = "#FEF9C3";
const DANGER_BG = "#FEE2E2";
const DANGER_TEXT = "#EF4444";
const DAYS = ["일", "월", "화", "수", "목", "금", "토"];
const WEEK_DAYS_ORDER = ["월", "화", "수", "목", "금", "토", "일"];
const COLORS = ["#10B981", "#3B82F6", "#8B5CF6", "#F97316", "#EC4899", "#14B8A6"];
const TIME_SLOT_LABEL: Record<TimeSlot, string> = {
  morning: "아침",
  lunch: "점심",
  evening: "저녁",
  bedtime: "취침 전",
};
const TIME_SLOT_PRESETS: Record<TimeSlot, string> = {
  morning: "08:00",
  lunch: "12:00",
  evening: "19:00",
  bedtime: "22:00",
};
const CONDITION_LABEL: Record<MealCondition, string> = {
  fasting: "공복",
  before: "식전",
  after: "식후",
  any: "무관",
};
const FORM_LABEL: Record<MedForm, string> = {
  oral: "💊 경구",
  injection: "💉 주사",
  other: "🧴 기타",
};
const SLOT_ORDER: TimeSlot[] = ["morning", "lunch", "evening", "bedtime"];
const STEPPER_MINUTES = [0, 15, 30, 45];

function generateId(): string {
  return `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
}

function pad(value: number): string {
  return String(value).padStart(2, "0");
}

function getDateKey(date: Date): string {
  return `${date.getFullYear()}-${pad(date.getMonth() + 1)}-${pad(date.getDate())}`;
}

function parseDateKey(dateStr: string): Date {
  const [year, month, day] = dateStr.split("-").map(Number);
  return new Date(year, month - 1, day);
}

function formatDateHeader(dateStr: string): string {
  const date = parseDateKey(dateStr);
  return `${date.getMonth() + 1}월 ${date.getDate()}일 ${DAYS[date.getDay()]}`;
}

function isMedicationScheduledOnDate(medication: Medication, dateStr: string): boolean {
  const dayName = DAYS[parseDateKey(dateStr).getDay()];
  if (!medication.isActive || medication.schedules.length === 0) {
    return false;
  }
  if (medication.frequency === "daily") {
    return true;
  }
  return medication.frequencyDays.includes(dayName);
}

function sortSchedules(schedules: MedSchedule[]): MedSchedule[] {
  return [...schedules].sort((a, b) => {
    const slotDiff = SLOT_ORDER.indexOf(a.timeSlot) - SLOT_ORDER.indexOf(b.timeSlot);
    if (slotDiff !== 0) {
      return slotDiff;
    }
    return a.timeDetail.localeCompare(b.timeDetail);
  });
}

function getCheckItemsForDate(
  medications: Medication[],
  logs: MedLog[],
  dateStr: string
): CheckItem[] {
  return medications
    .filter((medication) => isMedicationScheduledOnDate(medication, dateStr))
    .flatMap((medication) =>
      sortSchedules(medication.schedules).map((schedule) => ({
        medicationId: medication.id,
        scheduleId: schedule.id,
        name: medication.name,
        dosage: medication.dosage,
        condition: medication.condition,
        timeSlot: schedule.timeSlot,
        timeDetail: schedule.timeDetail,
        color: COLORS[medication.colorIndex % COLORS.length],
        log:
          logs.find(
            (log) =>
              log.medicationId === medication.id &&
              log.scheduleId === schedule.id &&
              log.date === dateStr
          ) ?? null,
      }))
    );
}

function isOverdue(timeDetail: string, log: MedLog | null, dateStr: string): boolean {
  if (log?.status === "taken") {
    return false;
  }

  const today = getDateKey(new Date());
  if (dateStr !== today) {
    return dateStr < today;
  }

  const [hour, minute] = timeDetail.split(":").map(Number);
  const scheduled = new Date();
  scheduled.setHours(hour, minute, 0, 0);

  return Date.now() - scheduled.getTime() > 30 * 60 * 1000;
}

function getNextWeeklyInfo(
  medication: Medication,
  today: string
): { dayName: string; daysUntil: number } | null {
  if (medication.frequency !== "weekly" || medication.frequencyDays.length === 0) {
    return null;
  }

  const todayDate = parseDateKey(today);
  const todayIndex = todayDate.getDay();
  const todayName = DAYS[todayIndex];
  if (medication.frequencyDays.includes(todayName)) {
    return null;
  }

  let nextDayName = "";
  let minDiff = 8;

  medication.frequencyDays.forEach((dayName) => {
    const targetIndex = DAYS.indexOf(dayName);
    if (targetIndex === -1) {
      return;
    }
    let diff = (targetIndex - todayIndex + 7) % 7;
    if (diff === 0) {
      diff = 7;
    }
    if (diff < minDiff) {
      minDiff = diff;
      nextDayName = dayName;
    }
  });

  return nextDayName ? { dayName: nextDayName, daysUntil: minDiff } : null;
}

function buildCalendarMatrix(year: number, month: number): (number | null)[][] {
  const firstDay = new Date(year, month, 1).getDay();
  const lastDate = new Date(year, month + 1, 0).getDate();
  const cells: (number | null)[] = [
    ...Array.from({ length: firstDay }, () => null),
    ...Array.from({ length: lastDate }, (_, index) => index + 1),
  ];

  while (cells.length % 7 !== 0) {
    cells.push(null);
  }

  const matrix: (number | null)[][] = [];
  for (let index = 0; index < cells.length; index += 7) {
    matrix.push(cells.slice(index, index + 7));
  }
  return matrix;
}

function getDayStatus(dateStr: string, medications: Medication[], logs: MedLog[]): DayStatus {
  const scheduledItems = getCheckItemsForDate(medications, logs, dateStr);
  if (scheduledItems.length === 0) {
    return "none";
  }

  const takenCount = scheduledItems.filter((item) => item.log?.status === "taken").length;
  const today = getDateKey(new Date());

  if (takenCount === scheduledItems.length) {
    return "complete";
  }
  if (takenCount > 0) {
    return "partial";
  }
  if (dateStr < today) {
    return "missed";
  }
  return "pending";
}

function getDayDots(dateStr: string, medications: Medication[], logs: MedLog[]): string[] {
  const colorMap = new Map(medications.map((medication) => [medication.id, medication]));
  const uniqueColors: string[] = [];

  logs
    .filter((log) => log.date === dateStr && log.status === "taken")
    .forEach((log) => {
      const medication = colorMap.get(log.medicationId);
      if (!medication) {
        return;
      }
      const color = COLORS[medication.colorIndex % COLORS.length];
      if (!uniqueColors.includes(color)) {
        uniqueColors.push(color);
      }
    });

  return uniqueColors.slice(0, 3);
}

function getWeekSummary(
  medications: Medication[],
  logs: MedLog[]
): { rate: number; missedCount: number } {
  const today = new Date();
  const monday = new Date(today);
  monday.setDate(today.getDate() - ((today.getDay() + 6) % 7));
  monday.setHours(0, 0, 0, 0);

  const sunday = new Date(monday);
  sunday.setDate(monday.getDate() + 6);

  const endDate = today < sunday ? today : sunday;
  endDate.setHours(0, 0, 0, 0);

  let totalScheduled = 0;
  let totalTaken = 0;
  let missedCount = 0;

  for (let cursor = new Date(monday); cursor <= endDate; cursor.setDate(cursor.getDate() + 1)) {
    const dateStr = getDateKey(cursor);
    const items = getCheckItemsForDate(medications, logs, dateStr);
    const takenCount = items.filter((item) => item.log?.status === "taken").length;

    totalScheduled += items.length;
    totalTaken += takenCount;

    if (dateStr < getDateKey(today)) {
      missedCount += items.length - takenCount;
    }
  }

  if (totalScheduled === 0) {
    return { rate: 0, missedCount: 0 };
  }

  return {
    rate: Math.round((totalTaken / totalScheduled) * 100),
    missedCount,
  };
}

function formatFrequencyLabel(medication: Medication): string {
  if (medication.frequency === "daily") {
    return "매일";
  }
  if (medication.frequencyDays.length === 0) {
    return "요일 미지정";
  }
  return `${medication.frequencyDays.join(" / ")} 요일`;
}

function CheckCard({ item, onToggle, date }: CheckCardProps) {
  const taken = item.log?.status === "taken";
  const overdue = isOverdue(item.timeDetail, item.log, date);

  return (
    <View style={[styles.checkCard, taken ? styles.checkCardTaken : null]}>
      <View style={[styles.checkDot, { backgroundColor: item.color }]} />
      <View style={styles.checkContent}>
        <Text style={[styles.checkName, taken ? styles.checkNameTaken : null]}>{item.name}</Text>
        <Text style={styles.checkMeta}>
          {item.dosage || "용량 없음"} · {CONDITION_LABEL[item.condition]} · {item.timeDetail}
        </Text>
        {overdue ? (
          <View style={styles.overdueBadge}>
            <Text style={styles.overdueBadgeText}>미복용</Text>
          </View>
        ) : null}
      </View>
      <TouchableOpacity
        activeOpacity={0.85}
        onPress={() => onToggle(item.medicationId, item.scheduleId, date)}
        style={[styles.checkButton, taken ? styles.checkButtonTaken : null]}
      >
        {taken ? <Text style={styles.checkButtonText}>✓</Text> : null}
      </TouchableOpacity>
    </View>
  );
}

function CalendarView({
  year,
  month,
  medications,
  logs,
  today,
  onPrevMonth,
  onNextMonth,
  onSelectDate,
}: CalendarViewProps) {
  const matrix = buildCalendarMatrix(year, month);

  return (
    <View style={[styles.card, styles.sectionSpacing]}>
      <View style={styles.calendarHeader}>
        <TouchableOpacity activeOpacity={0.8} onPress={onPrevMonth} style={styles.calendarArrowButton}>
          <Text style={styles.calendarArrowText}>‹</Text>
        </TouchableOpacity>
        <Text style={styles.calendarTitle}>
          {year}년 {month + 1}월
        </Text>
        <TouchableOpacity activeOpacity={0.8} onPress={onNextMonth} style={styles.calendarArrowButton}>
          <Text style={styles.calendarArrowText}>›</Text>
        </TouchableOpacity>
      </View>

      <View style={styles.weekDaysRow}>
        {DAYS.map((day) => (
          <View key={day} style={styles.weekDayCell}>
            <Text style={styles.weekDayText}>{day}</Text>
          </View>
        ))}
      </View>

      {matrix.map((week, weekIndex) => (
        <View key={`week-${weekIndex}`} style={styles.calendarWeekRow}>
          {week.map((day, dayIndex) => {
            if (day === null) {
              return <View key={`empty-${weekIndex}-${dayIndex}`} style={styles.calendarCell} />;
            }

            const dateStr = `${year}-${pad(month + 1)}-${pad(day)}`;
            const status = getDayStatus(dateStr, medications, logs);
            const dots = getDayDots(dateStr, medications, logs);
            const isToday = dateStr === today;
            const isFuture = dateStr > today;

            const circleStyles = [
              styles.calendarDayCircle,
              !isFuture && status === "complete" ? styles.calendarDayComplete : null,
              !isFuture && status === "partial" ? styles.calendarDayPartial : null,
              !isFuture && status === "missed" ? styles.calendarDayMissed : null,
              isToday ? styles.calendarDayToday : null,
            ];

            const textStyles = [
              styles.calendarDayText,
              !isFuture && status === "complete" ? styles.calendarDayCompleteText : null,
              !isFuture && status === "missed" ? styles.calendarDayMissedText : null,
              isFuture ? styles.calendarDayFutureText : null,
            ];

            return (
              <TouchableOpacity
                key={dateStr}
                activeOpacity={0.85}
                disabled={isFuture}
                onPress={() => onSelectDate(dateStr)}
                style={styles.calendarCell}
              >
                <View style={circleStyles}>
                  <Text style={textStyles}>{day}</Text>
                </View>
                <View style={styles.calendarDotsRow}>
                  {!isFuture
                    ? dots.map((color, index) => (
                        <View
                          key={`${dateStr}-${color}-${index}`}
                          style={[styles.calendarDot, { backgroundColor: color }]}
                        />
                      ))
                    : null}
                </View>
              </TouchableOpacity>
            );
          })}
        </View>
      ))}
    </View>
  );
}

function DateDetailSheet({
  visible,
  date,
  medications,
  logs,
  onClose,
  onToggleLog,
}: DateDetailSheetProps) {
  const items = date ? getCheckItemsForDate(medications, logs, date) : [];

  return (
    <Modal visible={visible} transparent animationType="slide" onRequestClose={onClose}>
      <View style={styles.modalOverlay}>
        <TouchableOpacity activeOpacity={1} onPress={onClose} style={styles.modalBackdrop} />
        <View style={styles.sheet}>
          <View style={styles.sheetHandle} />
          <Text style={styles.sheetTitle}>{date ? formatDateHeader(date) : ""}</Text>
          <ScrollView showsVerticalScrollIndicator={false}>
            {items.length === 0 ? (
              <Text style={styles.emptySheetText}>이 날은 복약 항목이 없습니다.</Text>
            ) : (
              items.map((item) => (
                <CheckCard
                  key={`${item.medicationId}-${item.scheduleId}-${date}`}
                  item={item}
                  onToggle={onToggleLog}
                  date={date ?? getDateKey(new Date())}
                />
              ))
            )}
          </ScrollView>
        </View>
      </View>
    </Modal>
  );
}

function MainScreen({
  medications,
  logs,
  calendarYear,
  calendarMonth,
  setCalendarYear,
  setCalendarMonth,
  onGoManage,
  onGoAdd,
  onToggleLog,
  onSelectDate,
}: MainScreenProps) {
  const today = getDateKey(new Date());
  const checkItems = getCheckItemsForDate(medications, logs, today);
  const doneCount = checkItems.filter((item) => item.log?.status === "taken").length;
  const totalCount = checkItems.length;
  const progress = totalCount === 0 ? 0 : (doneCount / totalCount) * 100;
  const weekSummary = getWeekSummary(medications, logs);
  const nextItems = medications
    .filter((medication) => medication.isActive && medication.frequency === "weekly")
    .map((medication) => ({
      medication,
      next: getNextWeeklyInfo(medication, today),
    }))
    .filter(
      (item): item is { medication: Medication; next: { dayName: string; daysUntil: number } } =>
        item.next !== null
    );

  const goPrevMonth = () => {
    if (calendarMonth === 0) {
      setCalendarYear(calendarYear - 1);
      setCalendarMonth(11);
      return;
    }
    setCalendarMonth(calendarMonth - 1);
  };

  const goNextMonth = () => {
    if (calendarMonth === 11) {
      setCalendarYear(calendarYear + 1);
      setCalendarMonth(0);
      return;
    }
    setCalendarMonth(calendarMonth + 1);
  };

  if (medications.length === 0) {
    return (
      <SafeAreaView style={styles.screen}>
        <ScrollView
          style={styles.screen}
          contentContainerStyle={styles.emptyContent}
          showsVerticalScrollIndicator={false}
        >
          <View style={styles.mainHeader}>
            <Text style={styles.mainHeaderTitle}>투약 관리</Text>
            <TouchableOpacity activeOpacity={0.85} onPress={onGoManage}>
              <Text style={styles.headerActionText}>약 관리</Text>
            </TouchableOpacity>
          </View>

          <View style={styles.emptyCard}>
            <Text style={styles.emptyIcon}>💊</Text>
            <Text style={styles.emptyTitle}>복용 중인 약을 등록해 주세요</Text>
            <Text style={styles.emptyDescription}>
              약을 등록하면 오늘 복약 체크, 달력 기록, 주간 요약을 한 번에 관리할 수 있습니다.
            </Text>
            <TouchableOpacity activeOpacity={0.88} onPress={onGoAdd} style={styles.primaryCta}>
              <Text style={styles.primaryCtaText}>약 등록하기</Text>
            </TouchableOpacity>
          </View>
        </ScrollView>
      </SafeAreaView>
    );
  }

  return (
    <SafeAreaView style={styles.screen}>
      <ScrollView
        style={styles.screen}
        contentContainerStyle={styles.mainContent}
        showsVerticalScrollIndicator={false}
      >
        <View style={styles.mainHeader}>
          <Text style={styles.mainHeaderTitle}>투약 관리</Text>
          <TouchableOpacity activeOpacity={0.85} onPress={onGoManage}>
            <Text style={styles.headerActionText}>약 관리</Text>
          </TouchableOpacity>
        </View>

        <TouchableOpacity activeOpacity={0.88} onPress={onGoManage} style={styles.summaryBanner}>
          <View style={styles.summaryBannerHeader}>
            <Text style={styles.summaryBannerTitle}>내 약 요약</Text>
            <Text style={styles.summaryBannerArrow}>▸</Text>
          </View>
          <Text style={styles.summaryBannerText}>
            {medications
              .slice(0, 2)
              .map((medication) => medication.name)
              .join(" · ")}
            {medications.length > 2 ? ` 외 ${medications.length - 2}개` : ""}
          </Text>
        </TouchableOpacity>

        <View style={styles.todaySection}>
          <View style={styles.todayHeaderRow}>
            <Text style={styles.sectionTitle}>오늘의 복약</Text>
            <View style={styles.doneBadge}>
              <Text style={styles.doneBadgeText}>
                {doneCount}/{totalCount} 완료
              </Text>
            </View>
          </View>
          <Text style={styles.todayDateText}>{formatDateHeader(today)}</Text>
          <View style={styles.progressTrack}>
            <View style={[styles.progressFill, { width: `${progress}%` }]} />
          </View>
        </View>

        {SLOT_ORDER.map((slot) => {
          const slotItems = checkItems.filter((item) => item.timeSlot === slot);
          if (slotItems.length === 0) {
            return null;
          }
          return (
            <View key={slot} style={styles.sectionBlock}>
              <Text style={styles.slotHeader}>{TIME_SLOT_LABEL[slot]}</Text>
              {slotItems.map((item) => (
                <CheckCard
                  key={`${item.medicationId}-${item.scheduleId}`}
                  item={item}
                  onToggle={onToggleLog}
                  date={today}
                />
              ))}
            </View>
          );
        })}

        {nextItems.length > 0 ? (
          <View style={styles.sectionBlock}>
            <Text style={styles.sectionTitle}>다음 예정</Text>
            {nextItems.map(({ medication, next }) => (
              <View key={medication.id} style={styles.nextCard}>
                <View
                  style={[
                    styles.nextDot,
                    { backgroundColor: COLORS[medication.colorIndex % COLORS.length] },
                  ]}
                />
                <Text style={styles.nextCardTitle}>{medication.name}</Text>
                <Text style={styles.nextCardMeta}>
                  {next.dayName}요일 · {next.daysUntil}일 후
                </Text>
              </View>
            ))}
          </View>
        ) : null}

        <CalendarView
          year={calendarYear}
          month={calendarMonth}
          medications={medications}
          logs={logs}
          today={today}
          onPrevMonth={goPrevMonth}
          onNextMonth={goNextMonth}
          onSelectDate={onSelectDate}
        />

        <View style={[styles.card, styles.weekSummaryCard]}>
          <Text style={styles.sectionTitle}>주간 요약</Text>
          <View style={styles.weekSummaryRow}>
            <View style={styles.weekSummaryItem}>
              <Text style={styles.weekSummaryValue}>{weekSummary.rate}%</Text>
              <Text style={styles.weekSummaryLabel}>복약률</Text>
            </View>
            <View style={styles.weekDivider} />
            <View style={styles.weekSummaryItem}>
              <Text style={[styles.weekSummaryValue, styles.weekSummaryMissedValue]}>
                {weekSummary.missedCount}회
              </Text>
              <Text style={styles.weekSummaryLabel}>놓친 횟수</Text>
