function AddScreen({ onBack, onSave }: AddScreenProps) {
  const [draft, setDraft] = useState<MedDraft>({
    name: "",
    form: "oral",
    dosage: "",
    frequency: "daily",
    frequencyDays: [],
    schedules: [],
    condition: "any",
    memo: "",
  });
  const [showTimeSheet, setShowTimeSheet] = useState(false);
  const [stepperHour, setStepperHour] = useState(8);
  const [stepperMinute, setStepperMinute] = useState(0);
  const [stepperSlot, setStepperSlot] = useState<TimeSlot>("morning");
  const [saving, setSaving] = useState(false);

  const canSave = draft.name.trim().length > 0 && draft.schedules.length > 0 && !saving;

  const updateDraft = <K extends keyof MedDraft>(key: K, value: MedDraft[K]) => {
    setDraft((prev) => ({ ...prev, [key]: value }));
  };

  const toggleFreqDay = (day: string) => {
    setDraft((prev) => ({
      ...prev,
      frequencyDays: prev.frequencyDays.includes(day)
        ? prev.frequencyDays.filter((item) => item !== day)
        : [...prev.frequencyDays, day],
    }));
  };

  const addScheduleFromPreset = (slot: TimeSlot) => {
    if (draft.schedules.some((schedule) => schedule.timeSlot === slot)) {
      return;
    }
    const nextSchedules = sortSchedules([
      ...draft.schedules,
      {
        id: generateId(),
        timeSlot: slot,
        timeDetail: TIME_SLOT_PRESETS[slot],
      },
    ]);
    updateDraft("schedules", nextSchedules);
    setShowTimeSheet(false);
  };

  const addScheduleCustom = () => {
    const timeDetail = `${pad(stepperHour)}:${pad(stepperMinute)}`;
    const nextSchedules = sortSchedules([
      ...draft.schedules,
      {
        id: generateId(),
        timeSlot: stepperSlot,
        timeDetail,
      },
    ]);
    updateDraft("schedules", nextSchedules);
    setShowTimeSheet(false);
  };

  const removeSchedule = (scheduleId: string) => {
    updateDraft(
      "schedules",
      draft.schedules.filter((schedule) => schedule.id !== scheduleId)
    );
  };

  const stepHour = (direction: 1 | -1) => {
    setStepperHour((prev) => (prev + direction + 24) % 24);
  };

  const stepMinute = (direction: 1 | -1) => {
    const currentIndex = STEPPER_MINUTES.indexOf(stepperMinute);
    const nextIndex = (currentIndex + direction + STEPPER_MINUTES.length) % STEPPER_MINUTES.length;
    setStepperMinute(STEPPER_MINUTES[nextIndex]);
  };

  const handleSave = async () => {
    if (!draft.name.trim()) {
      Alert.alert("안내", "약 이름을 입력해 주세요.");
      return;
    }
    if (draft.schedules.length === 0) {
      Alert.alert("안내", "복용 시간대를 하나 이상 추가해 주세요.");
      return;
    }

    setSaving(true);
    try {
      await onSave({
        ...draft,
        name: draft.name.trim(),
        dosage: draft.dosage.trim(),
        memo: draft.memo.trim(),
        schedules: sortSchedules(draft.schedules),
      });
    } finally {
      setSaving(false);
    }
  };

  return (
    <SafeAreaView style={styles.screen}>
      <View style={styles.subHeader}>
        <TouchableOpacity activeOpacity={0.8} onPress={onBack} style={styles.headerIconButton}>
          <Text style={styles.headerIconText}>←</Text>
        </TouchableOpacity>
        <Text style={styles.subHeaderTitle}>약 등록</Text>
        <TouchableOpacity
          activeOpacity={0.85}
          onPress={handleSave}
          disabled={!canSave}
          style={styles.headerSaveButton}
        >
          <Text style={[styles.headerSaveButtonText, !canSave ? styles.disabledText : null]}>
            {saving ? "저장 중" : "저장"}
          </Text>
        </TouchableOpacity>
      </View>

      <KeyboardAvoidingView
        style={styles.flex}
        behavior={Platform.OS === "ios" ? "padding" : undefined}
      >
        <ScrollView
          contentContainerStyle={styles.addContent}
          showsVerticalScrollIndicator={false}
          keyboardShouldPersistTaps="handled"
        >
          <Text style={styles.sectionLabel}>약 이름 *</Text>
          <TextInput
            value={draft.name}
            onChangeText={(value) => updateDraft("name", value)}
            placeholder="예: 위고비, 혈압약, 유산균"
            placeholderTextColor={SUBTEXT}
            style={styles.input}
          />

          <Text style={styles.sectionLabel}>복용 형태</Text>
          <View style={styles.formRow}>
            {(["oral", "injection", "other"] as MedForm[]).map((form, index) => (
              <TouchableOpacity
                key={form}
                activeOpacity={0.85}
                onPress={() => updateDraft("form", form)}
                style={[
                  styles.segmentButton,
                  index > 0 ? styles.segmentGap : null,
                  draft.form === form ? styles.segmentButtonActive : null,
                ]}
              >
                <Text
                  style={[
                    styles.segmentButtonText,
                    draft.form === form ? styles.segmentButtonTextActive : null,
                  ]}
                >
                  {FORM_LABEL[form]}
                </Text>
              </TouchableOpacity>
            ))}
          </View>

          <Text style={styles.sectionLabel}>용량</Text>
          <TextInput
            value={draft.dosage}
            onChangeText={(value) => updateDraft("dosage", value)}
            placeholder="예: 0.5mg, 1정, 2캡슐"
            placeholderTextColor={SUBTEXT}
            style={styles.input}
          />

          <Text style={styles.sectionLabel}>복용 주기</Text>
          <View style={styles.formRow}>
            {(["daily", "weekly"] as FreqType[]).map((frequency, index) => (
              <TouchableOpacity
                key={frequency}
                activeOpacity={0.85}
                onPress={() => updateDraft("frequency", frequency)}
                style={[
                  styles.segmentButton,
                  index > 0 ? styles.segmentGap : null,
                  draft.frequency === frequency ? styles.segmentButtonActive : null,
                ]}
              >
                <Text
                  style={[
                    styles.segmentButtonText,
                    draft.frequency === frequency ? styles.segmentButtonTextActive : null,
                  ]}
                >
                  {frequency === "daily" ? "매일" : "요일 지정"}
                </Text>
              </TouchableOpacity>
            ))}
          </View>

          {draft.frequency === "weekly" ? (
            <View style={styles.daysWrap}>
              {WEEK_DAYS_ORDER.map((day) => {
                const selected = draft.frequencyDays.includes(day);
                return (
                  <TouchableOpacity
                    key={day}
                    activeOpacity={0.85}
                    onPress={() => toggleFreqDay(day)}
                    style={[styles.dayChip, selected ? styles.dayChipActive : null]}
                  >
                    <Text style={[styles.dayChipText, selected ? styles.dayChipTextActive : null]}>
                      {day}
                    </Text>
                  </TouchableOpacity>
                );
              })}
            </View>
          ) : null}

          <Text style={styles.sectionLabel}>복용 시간대</Text>
          {draft.schedules.map((schedule) => (
            <View key={schedule.id} style={styles.scheduleCard}>
              <Text style={styles.scheduleTitle}>{TIME_SLOT_LABEL[schedule.timeSlot]}</Text>
              <Text style={styles.scheduleTime}>{schedule.timeDetail}</Text>
              <TouchableOpacity activeOpacity={0.8} onPress={() => removeSchedule(schedule.id)}>
                <Text style={styles.scheduleDelete}>✕</Text>
              </TouchableOpacity>
            </View>
          ))}

          <TouchableOpacity
            activeOpacity={0.88}
            onPress={() => setShowTimeSheet(true)}
            style={styles.addTimeButton}
          >
            <Text style={styles.addTimeButtonText}>+ 시간대 추가</Text>
          </TouchableOpacity>

          <Text style={styles.sectionLabel}>복용 조건</Text>
          <View style={styles.conditionWrap}>
            {(["fasting", "before", "after", "any"] as MealCondition[]).map((condition) => (
              <TouchableOpacity
                key={condition}
                activeOpacity={0.85}
                onPress={() => updateDraft("condition", condition)}
                style={[
                  styles.conditionButton,
                  draft.condition === condition ? styles.conditionButtonActive : null,
                ]}
              >
                <Text
                  style={[
                    styles.conditionButtonText,
                    draft.condition === condition ? styles.conditionButtonTextActive : null,
                  ]}
                >
                  {CONDITION_LABEL[condition]}
                </Text>
              </TouchableOpacity>
            ))}
          </View>

          <Text style={styles.sectionLabel}>메모</Text>
          <TextInput
            value={draft.memo}
            onChangeText={(value) => updateDraft("memo", value)}
            placeholder="특이사항을 입력해 주세요"
            placeholderTextColor={SUBTEXT}
            multiline
            numberOfLines={4}
            style={[styles.input, styles.memoInput]}
          />
        </ScrollView>
      </KeyboardAvoidingView>

      <Modal visible={showTimeSheet} transparent animationType="slide" onRequestClose={() => setShowTimeSheet(false)}>
        <View style={styles.modalOverlay}>
          <TouchableOpacity
            activeOpacity={1}
            onPress={() => setShowTimeSheet(false)}
            style={styles.modalBackdrop}
          />
          <View style={styles.sheet}>
            <View style={styles.sheetHandle} />
            <Text style={styles.sheetTitle}>시간대 추가</Text>

            <Text style={styles.sheetSectionLabel}>빠른 선택</Text>
            <View style={styles.presetWrap}>
              {SLOT_ORDER.map((slot) => {
                const disabled = draft.schedules.some((schedule) => schedule.timeSlot === slot);
                return (
                  <TouchableOpacity
                    key={slot}
                    activeOpacity={0.85}
                    disabled={disabled}
                    onPress={() => addScheduleFromPreset(slot)}
                    style={[
                      styles.presetButton,
                      disabled ? styles.presetButtonDisabled : styles.presetButtonActive,
                    ]}
                  >
                    <Text style={[styles.presetButtonText, disabled ? styles.disabledText : null]}>
                      {TIME_SLOT_LABEL[slot]} {TIME_SLOT_PRESETS[slot]}
                    </Text>
                  </TouchableOpacity>
                );
              })}
            </View>

            <Text style={styles.sheetSectionLabel}>직접 입력</Text>
            <View style={styles.stepperSlotWrap}>
              {SLOT_ORDER.map((slot) => (
                <TouchableOpacity
                  key={slot}
                  activeOpacity={0.85}
                  onPress={() => setStepperSlot(slot)}
                  style={[
                    styles.stepperSlotButton,
                    stepperSlot === slot ? styles.stepperSlotButtonActive : null,
                  ]}
                >
                  <Text
                    style={[
                      styles.stepperSlotText,
                      stepperSlot === slot ? styles.stepperSlotTextActive : null,
                    ]}
                  >
                    {TIME_SLOT_LABEL[slot]}
                  </Text>
                </TouchableOpacity>
              ))}
            </View>

            <View style={styles.timeStepperRow}>
              <View style={styles.timeStepperColumn}>
                <TouchableOpacity activeOpacity={0.8} onPress={() => stepHour(1)} style={styles.stepperArrowButton}>
                  <Text style={styles.stepperArrowText}>▲</Text>
                </TouchableOpacity>
                <Text style={styles.stepperValue}>{pad(stepperHour)}</Text>
                <TouchableOpacity activeOpacity={0.8} onPress={() => stepHour(-1)} style={styles.stepperArrowButton}>
                  <Text style={styles.stepperArrowText}>▼</Text>
                </TouchableOpacity>
              </View>

              <Text style={styles.stepperColon}>:</Text>

              <View style={styles.timeStepperColumn}>
                <TouchableOpacity
                  activeOpacity={0.8}
                  onPress={() => stepMinute(1)}
                  style={styles.stepperArrowButton}
                >
                  <Text style={styles.stepperArrowText}>▲</Text>
                </TouchableOpacity>
                <Text style={styles.stepperValue}>{pad(stepperMinute)}</Text>
                <TouchableOpacity
                  activeOpacity={0.8}
                  onPress={() => stepMinute(-1)}
                  style={styles.stepperArrowButton}
                >
                  <Text style={styles.stepperArrowText}>▼</Text>
                </TouchableOpacity>
              </View>
            </View>

            <TouchableOpacity activeOpacity={0.88} onPress={addScheduleCustom} style={styles.primaryBtn}>
              <Text style={styles.primaryBtnText}>추가</Text>
            </TouchableOpacity>
          </View>
        </View>
      </Modal>
    </SafeAreaView>
  );
}

export default function InjectionScreen() {
  const now = new Date();
  const [screen, setScreen] = useState<Screen>("main");
  const [medications, setMedications] = useState<Medication[]>([]);
  const [logs, setLogs] = useState<MedLog[]>([]);
  const [calendarYear, setCalendarYear] = useState(now.getFullYear());
  const [calendarMonth, setCalendarMonth] = useState(now.getMonth());
  const [selectedDate, setSelectedDate] = useState<string | null>(null);
  const [showDateSheet, setShowDateSheet] = useState(false);

  const toggleCheck = (medicationId: string, scheduleId: string, date = getDateKey(new Date())) => {
    setLogs((prev) => {
      const existing = prev.find(
        (log) =>
          log.medicationId === medicationId &&
          log.scheduleId === scheduleId &&
          log.date === date
      );

      if (existing) {
        if (existing.status === "taken") {
          return prev.map((log) =>
            log === existing ? { ...log, status: "pending", checkedAt: null } : log
          );
        }

        return prev.map((log) =>
          log === existing
            ? { ...log, status: "taken", checkedAt: new Date().toISOString() }
            : log
        );
      }

      return [
        ...prev,
        {
          id: generateId(),
          medicationId,
          scheduleId,
          date,
          status: "taken",
          checkedAt: new Date().toISOString(),
        },
      ];
    });
  };

  const handleAddMedication = async (draft: MedDraft) => {
    try {
      await createInjection({
        drug: draft.name,
        dosageMg: 0,
        site: "none",
        injectedAt: new Date().toISOString(),
        memo: draft.memo || `${draft.dosage || "용량 없음"} / ${CONDITION_LABEL[draft.condition]}`,
      });
    } catch (error) {
      console.warn("createInjection failed:", error);
    }

    const newMedication: Medication = {
      id: generateId(),
      name: draft.name,
      form: draft.form,
      dosage: draft.dosage,
      frequency: draft.frequency,
      frequencyDays: draft.frequencyDays,
      schedules: sortSchedules(draft.schedules),
      condition: draft.condition,
      memo: draft.memo,
      colorIndex: medications.length % COLORS.length,
      isActive: true,
      createdAt: new Date().toISOString(),
    };

    setMedications((prev) => [...prev, newMedication]);
    setScreen("main");
  };

  const handleDeleteMedication = (id: string) => {
    setMedications((prev) => prev.filter((medication) => medication.id !== id));
    setLogs((prev) => prev.filter((log) => log.medicationId !== id));
  };

  return (
    <View style={styles.screen}>
      {screen === "main" ? (
        <MainScreen
          medications={medications}
          logs={logs}
          calendarYear={calendarYear}
          calendarMonth={calendarMonth}
          setCalendarYear={setCalendarYear}
          setCalendarMonth={setCalendarMonth}
          onGoManage={() => setScreen("manage")}
          onGoAdd={() => setScreen("add")}
          onToggleLog={toggleCheck}
          onSelectDate={(date) => {
            setSelectedDate(date);
            setShowDateSheet(true);
          }}
        />
      ) : null}

      {screen === "manage" ? (
        <ManageScreen
          medications={medications}
          onBack={() => setScreen("main")}
          onGoAdd={() => setScreen("add")}
          onDelete={handleDeleteMedication}
        />
      ) : null}

      {screen === "add" ? (
        <AddScreen onBack={() => setScreen("main")} onSave={handleAddMedication} />
      ) : null}

      <DateDetailSheet
        visible={showDateSheet}
        date={selectedDate}
        medications={medications}
        logs={logs}
        onClose={() => setShowDateSheet(false)}
        onToggleLog={toggleCheck}
      />
    </View>
  );
}

