const DAYS = ["일", "월", "화", "수", "목", "금", "토"];
const WEEK_DAYS_ORDER = ["월", "화", "수", "목", "금", "토", "일"];
const COLORS = ["#10B981", "#3B82F6", "#8B5CF6", "#F97316", "#EC4899", "#14B8A6"];
const TIME_SLOT_LABEL: Record<TimeSlot, string> = {
