  oral: "💊 경구",
  injection: "💉 주사",
  other: "🧴 기타",
};
const SLOT_ORDER: TimeSlot[] = ["morning", "lunch", "evening", "bedtime"];
const STEPPER_MINUTES = [0, 15, 30, 45];

function generateId(): string {
  return `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
}

function pad(value: number): string {
  return String(value).padStart(2, "0");
}

function getDateKey(date: Date): string {
  return `${date.getFullYear()}-${pad(date.getMonth() + 1)}-${pad(date.getDate())}`;
}

function parseDateKey(dateStr: string): Date {
  const [year, month, day] = dateStr.split("-").map(Number);
  return new Date(year, month - 1, day);
}

function formatDateHeader(dateStr: string): string {
  const date = parseDateKey(dateStr);
  return `${date.getMonth() + 1}월 ${date.getDate()}일 ${DAYS[date.getDay()]}`;
}

function isMedicationScheduledOnDate(medication: Medication, dateStr: string): boolean {
  const dayName = DAYS[parseDateKey(dateStr).getDay()];
  if (!medication.isActive || medication.schedules.length === 0) {
    return false;
  }
  if (medication.frequency === "daily") {
    return true;
  }
  return medication.frequencyDays.includes(dayName);
}

function sortSchedules(schedules: MedSchedule[]): MedSchedule[] {
  return [...schedules].sort((a, b) => {
    const slotDiff = SLOT_ORDER.indexOf(a.timeSlot) - SLOT_ORDER.indexOf(b.timeSlot);
    if (slotDiff !== 0) {
      return slotDiff;
    }
    return a.timeDetail.localeCompare(b.timeDetail);
  });
}

function getCheckItemsForDate(
  medications: Medication[],
  logs: MedLog[],
  dateStr: string
): CheckItem[] {
  return medications
    .filter((medication) => isMedicationScheduledOnDate(medication, dateStr))
    .flatMap((medication) =>
      sortSchedules(medication.schedules).map((schedule) => ({
        medicationId: medication.id,
        scheduleId: schedule.id,
        name: medication.name,
        dosage: medication.dosage,
        condition: medication.condition,
        timeSlot: schedule.timeSlot,
        timeDetail: schedule.timeDetail,
        color: COLORS[medication.colorIndex % COLORS.length],
        log:
          logs.find(
            (log) =>
              log.medicationId === medication.id &&
              log.scheduleId === schedule.id &&
              log.date === dateStr
          ) ?? null,
      }))
    );
}

function isOverdue(timeDetail: string, log: MedLog | null, dateStr: string): boolean {
  if (log?.status === "taken") {
    return false;
  }

  const today = getDateKey(new Date());
  if (dateStr !== today) {
    return dateStr < today;
  }

  const [hour, minute] = timeDetail.split(":").map(Number);
  const scheduled = new Date();
  scheduled.setHours(hour, minute, 0, 0);

  return Date.now() - scheduled.getTime() > 30 * 60 * 1000;
}

function getNextWeeklyInfo(
  medication: Medication,
  today: string
): { dayName: string; daysUntil: number } | null {
  if (medication.frequency !== "weekly" || medication.frequencyDays.length === 0) {
    return null;
  }

  const todayDate = parseDateKey(today);
  const todayIndex = todayDate.getDay();
  const todayName = DAYS[todayIndex];
  if (medication.frequencyDays.includes(todayName)) {
    return null;
  }

  let nextDayName = "";
  let minDiff = 8;

  medication.frequencyDays.forEach((dayName) => {
    const targetIndex = DAYS.indexOf(dayName);
    if (targetIndex === -1) {
      return;
    }
    let diff = (targetIndex - todayIndex + 7) % 7;
    if (diff === 0) {
      diff = 7;
    }
    if (diff < minDiff) {
      minDiff = diff;
      nextDayName = dayName;
    }
  });

  return nextDayName ? { dayName: nextDayName, daysUntil: minDiff } : null;
}

function buildCalendarMatrix(year: number, month: number): (number | null)[][] {
  const firstDay = new Date(year, month, 1).getDay();
  const lastDate = new Date(year, month + 1, 0).getDate();
  const cells: (number | null)[] = [
    ...Array.from({ length: firstDay }, () => null),
    ...Array.from({ length: lastDate }, (_, index) => index + 1),
  ];

  while (cells.length % 7 !== 0) {
    cells.push(null);
  }

  const matrix: (number | null)[][] = [];
  for (let index = 0; index < cells.length; index += 7) {
    matrix.push(cells.slice(index, index + 7));
  }
  return matrix;
}

function getDayStatus(dateStr: string, medications: Medication[], logs: MedLog[]): DayStatus {
  const scheduledItems = getCheckItemsForDate(medications, logs, dateStr);
  if (scheduledItems.length === 0) {
    return "none";
  }

  const takenCount = scheduledItems.filter((item) => item.log?.status === "taken").length;
  const today = getDateKey(new Date());

  if (takenCount === scheduledItems.length) {
    return "complete";
  }
  if (takenCount > 0) {
    return "partial";
  }
  if (dateStr < today) {
    return "missed";
  }
  return "pending";
}

function getDayDots(dateStr: string, medications: Medication[], logs: MedLog[]): string[] {
  const colorMap = new Map(medications.map((medication) => [medication.id, medication]));
  const uniqueColors: string[] = [];

  logs
    .filter((log) => log.date === dateStr && log.status === "taken")
    .forEach((log) => {
      const medication = colorMap.get(log.medicationId);
      if (!medication) {
        return;
      }
      const color = COLORS[medication.colorIndex % COLORS.length];
      if (!uniqueColors.includes(color)) {
        uniqueColors.push(color);
      }
    });

  return uniqueColors.slice(0, 3);
}

function getWeekSummary(
  medications: Medication[],
  logs: MedLog[]
): { rate: number; missedCount: number } {
  const today = new Date();
  const monday = new Date(today);
  monday.setDate(today.getDate() - ((today.getDay() + 6) % 7));
  monday.setHours(0, 0, 0, 0);

  const sunday = new Date(monday);
  sunday.setDate(monday.getDate() + 6);

  const endDate = today < sunday ? today : sunday;
  endDate.setHours(0, 0, 0, 0);

  let totalScheduled = 0;
  let totalTaken = 0;
  let missedCount = 0;

  for (let cursor = new Date(monday); cursor <= endDate; cursor.setDate(cursor.getDate() + 1)) {
    const dateStr = getDateKey(cursor);
    const items = getCheckItemsForDate(medications, logs, dateStr);
    const takenCount = items.filter((item) => item.log?.status === "taken").length;

    totalScheduled += items.length;
    totalTaken += takenCount;

    if (dateStr < getDateKey(today)) {
      missedCount += items.length - takenCount;
    }
  }

  if (totalScheduled === 0) {
    return { rate: 0, missedCount: 0 };
  }

  return {
    rate: Math.round((totalTaken / totalScheduled) * 100),
    missedCount,
  };
}

function formatFrequencyLabel(medication: Medication): string {
  if (medication.frequency === "daily") {
    return "매일";
  }
  if (medication.frequencyDays.length === 0) {
    return "요일 미지정";
  }
  return `${medication.frequencyDays.join(" / ")} 요일`;
}

