function MainScreen({
  medications,
  logs,
  calendarYear,
  calendarMonth,
  setCalendarYear,
  setCalendarMonth,
  onGoManage,
  onGoAdd,
  onToggleLog,
  onSelectDate,
}: MainScreenProps) {
  const today = getDateKey(new Date());
  const checkItems = getCheckItemsForDate(medications, logs, today);
  const doneCount = checkItems.filter((item) => item.log?.status === "taken").length;
  const totalCount = checkItems.length;
  const progress = totalCount === 0 ? 0 : (doneCount / totalCount) * 100;
  const weekSummary = getWeekSummary(medications, logs);
  const nextItems = medications
    .filter((medication) => medication.isActive && medication.frequency === "weekly")
    .map((medication) => ({
      medication,
      next: getNextWeeklyInfo(medication, today),
    }))
    .filter(
      (item): item is { medication: Medication; next: { dayName: string; daysUntil: number } } =>
        item.next !== null
    );

  const goPrevMonth = () => {
    if (calendarMonth === 0) {
      setCalendarYear(calendarYear - 1);
      setCalendarMonth(11);
      return;
    }
    setCalendarMonth(calendarMonth - 1);
  };

  const goNextMonth = () => {
    if (calendarMonth === 11) {
      setCalendarYear(calendarYear + 1);
      setCalendarMonth(0);
      return;
    }
    setCalendarMonth(calendarMonth + 1);
  };

  if (medications.length === 0) {
    return (
      <SafeAreaView style={styles.screen}>
        <ScrollView
          style={styles.screen}
          contentContainerStyle={styles.emptyContent}
          showsVerticalScrollIndicator={false}
        >
          <View style={styles.mainHeader}>
            <Text style={styles.mainHeaderTitle}>투약 관리</Text>
            <TouchableOpacity activeOpacity={0.85} onPress={onGoManage}>
              <Text style={styles.headerActionText}>약 관리</Text>
            </TouchableOpacity>
          </View>

          <View style={styles.emptyCard}>
            <Text style={styles.emptyIcon}>💊</Text>
            <Text style={styles.emptyTitle}>복용 중인 약을 등록해 주세요</Text>
            <Text style={styles.emptyDescription}>
              약을 등록하면 오늘 복약 체크, 달력 기록, 주간 요약을 한 번에 관리할 수 있습니다.
            </Text>
            <TouchableOpacity activeOpacity={0.88} onPress={onGoAdd} style={styles.primaryCta}>
              <Text style={styles.primaryCtaText}>약 등록하기</Text>
            </TouchableOpacity>
          </View>
        </ScrollView>
      </SafeAreaView>
    );
  }

  return (
    <SafeAreaView style={styles.screen}>
      <ScrollView
        style={styles.screen}
        contentContainerStyle={styles.mainContent}
        showsVerticalScrollIndicator={false}
      >
        <View style={styles.mainHeader}>
          <Text style={styles.mainHeaderTitle}>투약 관리</Text>
          <TouchableOpacity activeOpacity={0.85} onPress={onGoManage}>
            <Text style={styles.headerActionText}>약 관리</Text>
          </TouchableOpacity>
        </View>

        <TouchableOpacity activeOpacity={0.88} onPress={onGoManage} style={styles.summaryBanner}>
          <View style={styles.summaryBannerHeader}>
            <Text style={styles.summaryBannerTitle}>내 약 요약</Text>
            <Text style={styles.summaryBannerArrow}>▸</Text>
          </View>
          <Text style={styles.summaryBannerText}>
            {medications
              .slice(0, 2)
              .map((medication) => medication.name)
              .join(" · ")}
            {medications.length > 2 ? ` 외 ${medications.length - 2}개` : ""}
          </Text>
        </TouchableOpacity>

        <View style={styles.todaySection}>
          <View style={styles.todayHeaderRow}>
            <Text style={styles.sectionTitle}>오늘의 복약</Text>
            <View style={styles.doneBadge}>
              <Text style={styles.doneBadgeText}>
                {doneCount}/{totalCount} 완료
              </Text>
            </View>
          </View>
          <Text style={styles.todayDateText}>{formatDateHeader(today)}</Text>
          <View style={styles.progressTrack}>
            <View style={[styles.progressFill, { width: `${progress}%` }]} />
          </View>
        </View>

        {SLOT_ORDER.map((slot) => {
          const slotItems = checkItems.filter((item) => item.timeSlot === slot);
          if (slotItems.length === 0) {
            return null;
          }
          return (
