function AddScreen({ onBack, onSave }: AddScreenProps) {
  const [draft, setDraft] = useState<MedDraft>({
    name: "",
    form: "oral",
    dosage: "",
    frequency: "daily",
    frequencyDays: [],
    schedules: [],
    condition: "any",
    memo: "",
  });
  const [showTimeSheet, setShowTimeSheet] = useState(false);
  const [stepperHour, setStepperHour] = useState(8);
  const [stepperMinute, setStepperMinute] = useState(0);
  const [stepperSlot, setStepperSlot] = useState<TimeSlot>("morning");
  const [saving, setSaving] = useState(false);

  const canSave = draft.name.trim().length > 0 && draft.schedules.length > 0 && !saving;

  const updateDraft = <K extends keyof MedDraft>(key: K, value: MedDraft[K]) => {
    setDraft((prev) => ({ ...prev, [key]: value }));
  };

  const toggleFreqDay = (day: string) => {
    setDraft((prev) => ({
      ...prev,
      frequencyDays: prev.frequencyDays.includes(day)
        ? prev.frequencyDays.filter((item) => item !== day)
        : [...prev.frequencyDays, day],
    }));
  };

  const addScheduleFromPreset = (slot: TimeSlot) => {
    if (draft.schedules.some((schedule) => schedule.timeSlot === slot)) {
      return;
    }
    const nextSchedules = sortSchedules([
      ...draft.schedules,
      {
        id: generateId(),
        timeSlot: slot,
        timeDetail: TIME_SLOT_PRESETS[slot],
      },
    ]);
    updateDraft("schedules", nextSchedules);
    setShowTimeSheet(false);
  };

  const addScheduleCustom = () => {
    const timeDetail = `${pad(stepperHour)}:${pad(stepperMinute)}`;
    const nextSchedules = sortSchedules([
      ...draft.schedules,
      {
        id: generateId(),
        timeSlot: stepperSlot,
        timeDetail,
      },
    ]);
    updateDraft("schedules", nextSchedules);
    setShowTimeSheet(false);
  };

  const removeSchedule = (scheduleId: string) => {
    updateDraft(
      "schedules",
      draft.schedules.filter((schedule) => schedule.id !== scheduleId)
    );
  };

  const stepHour = (direction: 1 | -1) => {
    setStepperHour((prev) => (prev + direction + 24) % 24);
  };

  const stepMinute = (direction: 1 | -1) => {
    const currentIndex = STEPPER_MINUTES.indexOf(stepperMinute);
    const nextIndex = (currentIndex + direction + STEPPER_MINUTES.length) % STEPPER_MINUTES.length;
    setStepperMinute(STEPPER_MINUTES[nextIndex]);
  };

  const handleSave = async () => {
    if (!draft.name.trim()) {
      Alert.alert("안내", "약 이름을 입력해 주세요.");
      return;
    }
    if (draft.schedules.length === 0) {
      Alert.alert("안내", "복용 시간대를 하나 이상 추가해 주세요.");
      return;
    }

    setSaving(true);
    try {
      await onSave({
        ...draft,
        name: draft.name.trim(),
        dosage: draft.dosage.trim(),
        memo: draft.memo.trim(),
        schedules: sortSchedules(draft.schedules),
      });
    } finally {
      setSaving(false);
    }
  };

  return (
    <SafeAreaView style={styles.screen}>
      <View style={styles.subHeader}>
        <TouchableOpacity activeOpacity={0.8} onPress={onBack} style={styles.headerIconButton}>
          <Text style={styles.headerIconText}>←</Text>
        </TouchableOpacity>
        <Text style={styles.subHeaderTitle}>약 등록</Text>
        <TouchableOpacity
          activeOpacity={0.85}
          onPress={handleSave}
          disabled={!canSave}
          style={styles.headerSaveButton}
        >
          <Text style={[styles.headerSaveButtonText, !canSave ? styles.disabledText : null]}>
            {saving ? "저장 중" : "저장"}
          </Text>
        </TouchableOpacity>
      </View>

      <KeyboardAvoidingView
        style={styles.flex}
        behavior={Platform.OS === "ios" ? "padding" : undefined}
      >
        <ScrollView
          contentContainerStyle={styles.addContent}
          showsVerticalScrollIndicator={false}
          keyboardShouldPersistTaps="handled"
        >
          <Text style={styles.sectionLabel}>약 이름 *</Text>
          <TextInput
            value={draft.name}
            onChangeText={(value) => updateDraft("name", value)}
            placeholder="예: 위고비, 혈압약, 유산균"
            placeholderTextColor={SUBTEXT}
            style={styles.input}
          />

          <Text style={styles.sectionLabel}>복용 형태</Text>
          <View style={styles.formRow}>
            {(["oral", "injection", "other"] as MedForm[]).map((form, index) => (
              <TouchableOpacity
                key={form}
                activeOpacity={0.85}
                onPress={() => updateDraft("form", form)}
                style={[
                  styles.segmentButton,
                  index > 0 ? styles.segmentGap : null,
                  draft.form === form ? styles.segmentButtonActive : null,
                ]}
              >
                <Text
                  style={[
                    styles.segmentButtonText,
                    draft.form === form ? styles.segmentButtonTextActive : null,
                  ]}
                >
                  {FORM_LABEL[form]}
                </Text>
              </TouchableOpacity>
            ))}
          </View>

          <Text style={styles.sectionLabel}>용량</Text>
          <TextInput
            value={draft.dosage}
            onChangeText={(value) => updateDraft("dosage", value)}
            placeholder="예: 0.5mg, 1정, 2캡슐"
            placeholderTextColor={SUBTEXT}
            style={styles.input}
          />

          <Text style={styles.sectionLabel}>복용 주기</Text>
          <View style={styles.formRow}>
            {(["daily", "weekly"] as FreqType[]).map((frequency, index) => (
              <TouchableOpacity
                key={frequency}
                activeOpacity={0.85}
                onPress={() => updateDraft("frequency", frequency)}
                style={[
                  styles.segmentButton,
                  index > 0 ? styles.segmentGap : null,
                  draft.frequency === frequency ? styles.segmentButtonActive : null,
                ]}
              >
                <Text
                  style={[
                    styles.segmentButtonText,
                    draft.frequency === frequency ? styles.segmentButtonTextActive : null,
                  ]}
                >
                  {frequency === "daily" ? "매일" : "요일 지정"}
                </Text>
              </TouchableOpacity>
            ))}
          </View>

          {draft.frequency === "weekly" ? (
            <View style={styles.daysWrap}>
              {WEEK_DAYS_ORDER.map((day) => {
                const selected = draft.frequencyDays.includes(day);
                return (
                  <TouchableOpacity
                    key={day}
                    activeOpacity={0.85}
                    onPress={() => toggleFreqDay(day)}
                    style={[styles.dayChip, selected ? styles.dayChipActive : null]}
                  >
                    <Text style={[styles.dayChipText, selected ? styles.dayChipTextActive : null]}>
                      {day}
                    </Text>
                  </TouchableOpacity>
                );
              })}
            </View>
          ) : null}

          <Text style={styles.sectionLabel}>복용 시간대</Text>
          {draft.schedules.map((schedule) => (
            <View key={schedule.id} style={styles.scheduleCard}>
              <Text style={styles.scheduleTitle}>{TIME_SLOT_LABEL[schedule.timeSlot]}</Text>
              <Text style={styles.scheduleTime}>{schedule.timeDetail}</Text>
              <TouchableOpacity activeOpacity={0.8} onPress={() => removeSchedule(schedule.id)}>
                <Text style={styles.scheduleDelete}>✕</Text>
              </TouchableOpacity>
            </View>
          ))}

          <TouchableOpacity
            activeOpacity={0.88}
            onPress={() => setShowTimeSheet(true)}
            style={styles.addTimeButton}
          >
            <Text style={styles.addTimeButtonText}>+ 시간대 추가</Text>
          </TouchableOpacity>

          <Text style={styles.sectionLabel}>복용 조건</Text>
          <View style={styles.conditionWrap}>
            {(["fasting", "before", "after", "any"] as MealCondition[]).map((condition) => (
              <TouchableOpacity
                key={condition}
                activeOpacity={0.85}
                onPress={() => updateDraft("condition", condition)}
                style={[
                  styles.conditionButton,
                  draft.condition === condition ? styles.conditionButtonActive : null,
                ]}
              >
                <Text
                  style={[
                    styles.conditionButtonText,
                    draft.condition === condition ? styles.conditionButtonTextActive : null,
                  ]}
                >
                  {CONDITION_LABEL[condition]}
                </Text>
              </TouchableOpacity>
            ))}
          </View>

          <Text style={styles.sectionLabel}>메모</Text>
          <TextInput
            value={draft.memo}
            onChangeText={(value) => updateDraft("memo", value)}
            placeholder="특이사항을 입력해 주세요"
            placeholderTextColor={SUBTEXT}
            multiline
            numberOfLines={4}
            style={[styles.input, styles.memoInput]}
          />
        </ScrollView>
      </KeyboardAvoidingView>

      <Modal visible={showTimeSheet} transparent animationType="slide" onRequestClose={() => setShowTimeSheet(false)}>
        <View style={styles.modalOverlay}>
          <TouchableOpacity
            activeOpacity={1}
            onPress={() => setShowTimeSheet(false)}
            style={styles.modalBackdrop}
          />
          <View style={styles.sheet}>
            <View style={styles.sheetHandle} />
            <Text style={styles.sheetTitle}>시간대 추가</Text>

            <Text style={styles.sheetSectionLabel}>빠른 선택</Text>
            <View style={styles.presetWrap}>
              {SLOT_ORDER.map((slot) => {
                const disabled = draft.schedules.some((schedule) => schedule.timeSlot === slot);
                return (
                  <TouchableOpacity
                    key={slot}
                    activeOpacity={0.85}
