                      {TIME_SLOT_LABEL[slot]} {TIME_SLOT_PRESETS[slot]}
                    </Text>
                  </TouchableOpacity>
                );
              })}
            </View>

            <Text style={styles.sheetSectionLabel}>직접 입력</Text>
            <View style={styles.stepperSlotWrap}>
              {SLOT_ORDER.map((slot) => (
                <TouchableOpacity
                  key={slot}
                  activeOpacity={0.85}
                  onPress={() => setStepperSlot(slot)}
